 9→function formatProjects(rows: Awaited<ReturnType<typeof listWorkspaceProjectSummaries>>): string {
10→  if (rows.length === 0) {
11→    return "- none";
12→  }
13→
14→  return rows
15→    .slice(0, 20)
16→    .map((row) => `- ${row.name} [id: ${row.id}] active tasks: ${row.activeTaskCount}`)
17→    .join("\n");
18→}
19→
20→function formatSuggestions(rows: SuggestionSummary[]): string {
21→  if (rows.length === 0) {
22→    return "- none";
23→  }
24→
25→  return rows
26→    .slice(0, 20)
27→    .map((row) => `- [${row.category}] ${row.text} (${row.status}, confidence ${row.confidence.toFixed(2)}, by ${row.suggestedBy})`)
28→    .join("\n");
29→}
30→
31→function formatObservations(rows: Awaited<ReturnType<typeof listWorkspaceOpenObservations>>): string {
32→  if (rows.length === 0) {
33→    return "- none";
34→  }
35→
36→  return rows
37→    .slice(0, 20)
38→    .map((row) => {
39→      const category = row.category ? `, ${row.category}` : "";
40→      return `- [${row.severity}] ${row.text} (${row.status}, by ${row.sourceAgent}${category})`;
41→    })
42→    .join("\n");
43→}
