 10→const workItemSuggestionSchema = z
 11→  .object({
 12→    kind: z.enum(["task", "feature", "project"]),
 13→    title: z.string().min(1),
 14→    rationale: z.string().min(1),
 15→    category: z.enum(["none", ...ENTITY_CATEGORIES]),
 16→    project: z.enum(["none"]).or(z.string().min(1)),
 17→    priority: z.enum(["none", ...ENTITY_PRIORITIES]),
 18→    possible_duplicate: z.enum(["none"]).or(
 19→      z.object({
 20→        id: z.string().min(1),
 21→        name: z.string().min(1),
 22→        similarity: z.number().min(0).max(1),
 23→      }),
 24→    ),
 25→  })
 26→  .transform((v) => ({
 27→    ...v,
 28→    category: v.category === "none" ? undefined : v.category,
 29→    project: v.project === "none" ? undefined : v.project,
 30→    priority: v.priority === "none" ? undefined : v.priority,
 31→    possible_duplicate: v.possible_duplicate === "none" ? undefined : v.possible_duplicate,
 32→  }));
 33→
 34→const pmAgentResultSchema = z.object({
 35→  summary: z.string().min(1),
 36→  suggestions: z.array(workItemSuggestionSchema),
 37→  updated: z.array(
 38→    z.object({
 39→      existing_id: z.string().min(1),
 40→      title: z.string().min(1),
 41→      changes: z.string().min(1),
 42→    }),
 43→  ),
 44→  discarded: z.array(
 45→    z.object({
 46→      title: z.string().min(1),
 47→      reason: z.string().min(1),
 48→    }),
 49→  ),
 50→  observations_created: z.array(z.string().min(1)),
 51→});
 52→
 53→export type WorkItemSuggestion = z.infer<typeof workItemSuggestionSchema>;
 54→export type PmAgentResult = z.infer<typeof pmAgentResultSchema>;
